       h.id,
       t.locale::public.profile_locale,
       'text',
       t.text
from public.hints h
join (values
  ('welcome', 'ca', 'Benvingut a Entertain! Comença pel catàleg —és la base de tot. Toca «Més…» per descobrir què pots fer.'),
  ('welcome', 'es', '¡Bienvenido a Entertain! Empieza por el catálogo —es la base de todo. Toca «Más…» para descubrir qué puedes hacer.'),
  ('welcome', 'en', 'Welcome to Entertain! Start with your catalog —it''s the base of everything. Tap "More…" to discover what you can do.'),
  ('ai_recipe', 'ca', 'Sabies que, si no tens la recepta, pots demanar-la a l''IA i t''afegeix el plat amb els ingredients automàticament?'),
  ('ai_recipe', 'es', '¿Sabías que, si no tienes la receta, puedes pedírsela a la IA y te añade el plato con los ingredientes automáticamente?'),
  ('ai_recipe', 'en', 'Did you know that if you don''t have the recipe, you can ask the AI and it adds the dish with its ingredients automatically?'),
