  ('help_icon', 'es', '¿Sabías que en cada pantalla tienes el icono ? con una explicación corta?'),
  ('help_icon', 'en', 'Did you know each screen has a ? icon with a short explanation?'),
  ('hints_toggle', 'ca', 'Sabies que pots desactivar aquestes pistes quan vulguis, i tornar-les a activar des de Configuració?'),
  ('hints_toggle', 'es', '¿Sabías que puedes desactivar estas pistas cuando quieras, y reactivarlas desde Configuración?'),
  ('hints_toggle', 'en', 'Did you know you can turn these tips off whenever you want, and back on from Settings?')
) as t(key, locale, text) on t.key = h.key
where not exists (
  select 1
  from public.translations existing
  where existing.entity_type = 'hint'::public.translation_entity_type
    and existing.entity_id = h.id
    and existing.locale = t.locale::public.profile_locale
    and existing.field = 'text'
);
